import Foundation

enum NetworkError: Error {
    case invalidURL
    case dataTaskError(Error)
}

struct UserDataResponse: Codable {}

class NetworkManager {
    private let baseURLString = "https://api.example.com"
    private let session = URLSession.shared

    func getUserData(completion: @escaping (Result<UserDataResponse, Error>) -> Void) {
        guard let url = URL(string: "\(baseURLString)/userdata") else {
            completion(.failure(NetworkError.invalidURL))
            return
        }

        var request = URLRequest(url: url)
        request.httpMethod = "GET"

        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(NetworkError.dataTaskError(error)))
                return
            }

            guard let data = data else {
                completion(.failure(NetworkError.dataTaskError(NSError(domain: "", code: -1001, userInfo: nil))))
                return
            }

            do {
                let decodedResponse = try JSONDecoder().decode(UserDataResponse.self, from: data)
                completion(.success(decodedResponse))
            } catch {
                completion(.failure(error))
            }
        }

        task.resume()
    }

    func postUserData(_ userData: Data, completion: @escaping (Result<Void, Error>) -> Void) {
        guard let url = URL(string: "\(baseURLString)/userdata") else {
            completion(.failure(NetworkError.invalidURL))
            return
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")

        let task = session.uploadTask(with: request, from: userData) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }

            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(NSError(domain: "", code: -1002, userInfo: nil)))
                return
            }

            if httpResponse.statusCode != 200 && httpResponse.statusCode != 201 {
                completion(.failure(NSError(domain: "", code: -1003, userInfo: ["statusCode": httpResponse.statusCode])))
            } else {
                completion(.success(()))
            }
        }

        task.resume()
    }
}